#include <iostream>
#include <stack>
using namespace std;
stack<int> sta;
int main()
{
    string s;
    cin>>s;
    s=s+'+';
    int num=0,sum=0;
    bool cheng=false;
    for(int i=0;i<=s.size()-1;i++)
    {

        if(s[i]>='0'&&s[i]<='9')
        {
            num=num*10+s[i]-'0';
        }
        else
        {
            if(cheng)
            {
                num=(num*sta.top())%10000;
                cheng=false;
                sta.pop();
            }
            sta.push(num);

            if(s[i]=='*')
            {
                cheng=true;
            }
            num=0;
        }
    }
    while(!(sta.empty()))
    {
        sum=(sum+sta.top())%10000;
        sta.pop();
    }
    cout<<sum%10000;
    return 0;
}
